import { useGLTF, Environment, ContactShadows, Sparkles } from "@react-three/drei";

export function Model() {
  const modelPath = "http://localhost:3000/public/uploads/3dmodels/ferrari_f8_tributo.glb";
  const { scene } = useGLTF(modelPath);

  return (
    <group>
      {/* Main Model */}
      <primitive
        object={scene}
        scale={1.5}
        position={[0, -0.5, 0]}
        rotation={[0, Math.PI / 4, 0]}
      />
      
      {/* Enhanced Background Elements */}
      <Environment preset="studio" background blur={0.5} />
      
      <ContactShadows
        position={[0, -0.5, 0]}
        opacity={0.75}
        scale={10}
        blur={2}
        far={5}
        color="#1a1a1a"
      />
      
      <Sparkles
        count={100}
        scale={8}
        size={2}
        speed={0.3}
        color="#00ffff"
        opacity={0.3}
      />
      
      {/* Animated Ground Plane */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]}>
        <circleGeometry args={[5, 64]} />
        <meshStandardMaterial
          color="#1a1a1a"
          metalness={0.8}
          roughness={0.3}
        />
      </mesh>
      
      {/* Decorative Wireframe Sphere */}
      <mesh position={[3, 1, -3]}>
        <sphereGeometry args={[0.5, 12, 12]} />
        <meshStandardMaterial
          color="#ff4444"
          wireframe
          transparent
          opacity={0.2}
        />
      </mesh>
    </group>
  );
}

// Preload assets
useGLTF.preload("http://localhost:3000/public/uploads/3dmodels/ferrari_f8_tributo.glb");
